module RefModule(
  input clk,
  input reset,
  output reg [3:0] count,
  output reg mod3
);reg [1:0] unused_mod_cnt;

  always @(posedge clk) begin
    if (reset) begin
      count <= 4'b0000;
      unused_mod_cnt <= 2'b00;
      mod3 <= 1'b0;
    end
    else begin
      count <= count + 1;
      unused_mod_cnt <= unused_mod_cnt + 1;
      if (unused_mod_cnt == 2'b10) begin
        unused_mod_cnt <= 2'b00;
        mod3 <= ~mod3;
      end
    end
  end

endmodule
